const API = process.env.REACT_APP_API_URL || "http://127.0.0.1:8000";

/* =========================
   HELPER (safe response handler)
========================= */
const handleResponse = async (res) => {
  const data = await res.json().catch(() => ({}));

  if (!res.ok) {
    throw new Error(data.detail || data.message || "Request failed");
  }

  return data;
};

/* =========================
   AUTH
========================= */
export const registerUser = async (data) => {
  const res = await fetch(`${API}/register`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(data),
  });

  return handleResponse(res);
};

export const loginUser = async (data) => {
  const res = await fetch(`${API}/login`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(data),
  });

  return handleResponse(res);
};

/* =========================
   PATIENTS
========================= */
export const getPatients = async () => {
  const res = await fetch(`${API}/patients/`);
  return handleResponse(res);
};

export const addPatient = async (data) => {
  const res = await fetch(`${API}/patients/`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(data),
  });

  return handleResponse(res);
};

/* =========================
   APPOINTMENTS
========================= */
export const getAppointments = async () => {
  const res = await fetch(`${API}/appointments/`);
  return handleResponse(res);
};

export const addAppointment = async (data) => {
  const res = await fetch(`${API}/appointments/`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(data),
  });

  return handleResponse(res);
};

/* =========================
   PRESCRIPTIONS
========================= */
export const addPrescription = async (data) => {
  const res = await fetch(`${API}/prescriptions/`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(data),
  });

  return handleResponse(res);
};

export const getPrescriptions = async (patientId) => {
  const res = await fetch(`${API}/prescriptions/${patientId}`);
  return handleResponse(res);
};

/* =========================
   SEARCH (optional backend usage)
========================= */
export const searchByPhone = async (phone) => {
  const res = await fetch(`${API}/patients/search/phone/${phone}`);
  return handleResponse(res);
};

export const searchById = async (id) => {
  const res = await fetch(`${API}/patients/search/id/${id}`);
  return handleResponse(res);
};
